# ── CALLBACKS ─────────────────────────────────────────────────────────────────

@app.callback(Output("ov-bar","figure"), Output("ov-kpis","children"),
              Input("ov-cat","value"), Input("ov-display","value"))
def update_overview(cat, display):
    pcts   = [OVERALL[cat][str(yr)] for yr in YEARS]
    y_vals = pcts
    fig = go.Figure(go.Bar(
        x=[str(y) for y in YEARS], y=y_vals,
        marker_color=["#1a5e5b" if v==max(y_vals) else "#2a8c87" for v in y_vals],
        text=[f"{v:.2f}%" for v in y_vals], textposition="outside",
    ))
    fig.update_layout(title=f"{LABELS[cat]} in Bulgaria (2020–2024)",
                      yaxis_title="% of firms", xaxis_title="Year",
                      plot_bgcolor="white", paper_bgcolor="white",
                      yaxis=dict(gridcolor="#e0f8f7"),
                      font=dict(family="Segoe UI", color="#1a5e5b"), margin=dict(t=60,b=40))
    peak_yr = YEARS[pcts.index(max(pcts))]
    delta   = round(pcts[-1]-pcts[0], 2)
    delta_s = f"+{delta}%" if delta>=0 else f"{delta}%"
    cards = [
        _card("2024 value", f"{pcts[-1]:.2f}%", "of firms"),
        _card("Peak year", str(peak_yr), f"{max(pcts):.2f}%"),
        _card("Change 2020→2024", delta_s, "percentage points", "#1a5e5b" if delta>=0 else "#c0392b"),
    ]
    return fig, cards

def _card(title, value, subtitle, color="#1a5e5b"):
    return html.Div(style={"backgroundColor":"white","border":f"2px solid {color}","borderRadius":"10px",
                            "padding":"16px 24px","minWidth":"160px","textAlign":"center",
                            "boxShadow":"2px 2px 8px rgba(0,0,0,0.07)"}, children=[
        html.P(title, style={"margin":0,"fontSize":"12px","color":"#888"}),
        html.H2(value, style={"margin":"4px 0","color":color,"fontSize":"28px"}),
        html.P(subtitle, style={"margin":0,"fontSize":"11px","color":"#aaa"}),
    ])

@app.callback(Output("ind-bar","figure"), Input("ind-year","value"), Input("ind-cat","value"))
def update_industry(year, cat):
    data = BY_INDUSTRY[year][cat]
    items = sorted(data.items(), key=lambda x: x[1])
    fig = go.Figure(go.Bar(
        x=[v for _,v in items], y=[k for k,_ in items], orientation="h",
        marker_color="#2a8c87",
        text=[f"{v:.2f}%" for _,v in items], textposition="outside",
    ))
    fig.update_layout(title=f"{LABELS[cat]} by Industry — Bulgaria {year}",
                      xaxis_title="% of firms", plot_bgcolor="white", paper_bgcolor="white",
                      xaxis=dict(gridcolor="#e0f8f7"), font=dict(family="Segoe UI",color="#1a5e5b"),
                      height=600, margin=dict(l=340,t=60,b=40))
    return fig

@app.callback(Output("reg-bar","figure"), Input("reg-year","value"), Input("reg-cat","value"))
def update_region(year, cat):
    data = BY_REGION[year][cat]
    items = sorted(data.items(), key=lambda x: x[1])
    fig = go.Figure(go.Bar(
        x=[v for _,v in items], y=[k for k,_ in items], orientation="h",
        marker_color=["#1a5e5b" if k=="Sofia City" else "#2a8c87" for k,_ in items],
        text=[f"{v:.2f}%" for _,v in items], textposition="outside",
    ))
    fig.update_layout(title=f"{LABELS[cat]} by Region — Bulgaria {year}",
                      xaxis_title="% of firms", plot_bgcolor="white", paper_bgcolor="white",
                      xaxis=dict(gridcolor="#e0f8f7"), font=dict(family="Segoe UI",color="#1a5e5b"),
                      height=650, margin=dict(l=160,t=60,b=40))
    return fig

@app.callback(Output("cmp-lines","figure"), Input("cmp-cats","value"))
def update_compare(selected):
    if not selected:
        return go.Figure()
    fig = go.Figure()
    for i, cat in enumerate(selected):
        pcts = [OVERALL[cat][str(yr)] for yr in YEARS]
        fig.add_trace(go.Scatter(
            x=[str(y) for y in YEARS], y=pcts, name=LABELS[cat],
            mode="lines+markers",
            line=dict(color=ESI_COLORS[i%len(ESI_COLORS)], width=3),
            marker=dict(size=8),
        ))
    fig.update_layout(title="Evolution of Growth Metrics — Bulgaria 2020–2024",
                      yaxis_title="% of firms", xaxis_title="Year",
                      plot_bgcolor="white", paper_bgcolor="white",
                      yaxis=dict(gridcolor="#e0f8f7"),
                      legend=dict(bgcolor="white",bordercolor="#ccc",borderwidth=1),
                      font=dict(family="Segoe UI",color="#1a5e5b"), margin=dict(t=60,b=40))
    return fig

